import torch.nn as nn
import torch.optim as optim
import numpy as np
import os

class Agent:
    def __init__(self):
        # Neural network for policy
        self.policy_network = nn.Sequential(
            nn.Linear(4, 64),
            nn.ReLU(),
            nn.Linear(64, 64),
            nn.ReLU(),
            nn.Linear(64, 2)  # 2 actions in CartPole
        )
        self.optimizer = optim.Adam(self.policy_network.parameters(), lr=0.001)

    def select_action(self, observation):
        # Convert observation to tensor
        obs_tensor = torch.FloatTensor(observation).unsqueeze(0)
        # Get action probabilities
        with torch.no_grad():
            logits = self.policy_network(obs_tensor)
            probs = torch.softmax(logits, dim=1)
        # Select action with highest probability
        action = probs.argmax().item()
        return action

    def save(self, directory):
        if not os.path.exists(directory):
            os.makedirs(directory)
        torch.save(self.policy_network.state_dict(), os.path.join(directory, 'policy_network.pth'))

    def load(self, directory):
        model_path = os.path.join(directory, 'policy_network.pth')
        if os.path.exists(model_path):
            self.policy_network.load_state_dict(torch.load(model_path))
        else:
